import { formatBytes } from '../../../../services/debug/db-info.js';
import {
    listCaches, clearCache, clearAllCaches,
    listDatabases, deleteDatabaseNamed, deleteAllDatabases,
    listLocalStorage, removeLocalStorageKey, clearLocalStorage,
    listSessionStorage, removeSessionStorageKey, clearSessionStorage,
    nukeAndReload,
    type CacheInfo, type WebStorageInfo,
} from '../../../../services/debug/storage-controls.js';

type StorageArea = 'caches' | 'idb' | 'local' | 'session';

const AREA_LABELS: Record<StorageArea, string> = {
    caches: 'Cache Storage',
    idb: 'IndexedDB',
    local: 'localStorage',
    session: 'sessionStorage',
};

// Matches the existing per-area "clear everything" test ids so flows and tests
// that targeted the old all-or-nothing buttons keep working.
const CLEAR_ALL_TESTID: Record<StorageArea, string> = {
    caches: 'storage-clear-caches',
    idb: 'storage-delete-idb',
    local: 'storage-clear-local',
    session: 'storage-clear-session',
};

// Best-effort, human-readable hints for the storage keys this app is known to
// use. Names absent from these maps simply render without a description — keep
// these in sync as storage keys/caches are added or renamed.
const HINTS: Record<StorageArea, Record<string, string>> = {
    caches: {
        'motivation-pwa-v3': 'App shell & static assets',
        'motivation-images-v1': 'Served images',
    },
    idb: {
        'motivation-image-uploads': 'Queued image uploads (pending sync)',
    },
    local: {
        'client-log.device-id': 'Device identity for client logging',
        'client-log.device-label': 'Device label',
        health_calorie_target: 'Calorie target setting',
        boot_breadcrumbs: 'Boot-failure diagnostics',
    },
    session: {
        'meal-in-flight-draft': 'In-progress meal draft',
        stale_bundle_reloaded: 'Stale-bundle reload guard',
    },
};

interface Row {
    name: string;
    meta: string;
    hint?: string;
}

const template = document.createElement('template');
template.innerHTML = `
<details class="debug-panel" open>
    <summary>Storage</summary>
    <div class="debug-storage" data-role="sections">Loading storage…</div>
    <pre class="debug-code" data-role="output" hidden></pre>
    <div class="debug-toolbar">
        <button class="debug-btn" type="button" data-testid="storage-refresh">Refresh</button>
        <button class="debug-btn" type="button" data-testid="storage-nuke">Nuke &amp; reload</button>
    </div>
</details>
`;

export class DebugStoragePanel extends HTMLElement {
    private initialized = false;
    private sectionsEl!: HTMLElement;
    private outputEl!: HTMLPreElement;

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        this.appendChild(template.content.cloneNode(true));

        this.sectionsEl = this.querySelector<HTMLElement>('[data-role="sections"]')!;
        this.outputEl = this.querySelector<HTMLPreElement>('[data-role="output"]')!;

        this.querySelector<HTMLButtonElement>('[data-testid="storage-refresh"]')!
            .addEventListener('click', () => { void this.refresh(); });

        this.querySelector<HTMLButtonElement>('[data-testid="storage-nuke"]')!
            .addEventListener('click', () => { void (async () => {
                if (!confirm('Unregister the service worker, clear all caches and IndexedDB, then reload?')) return;
                await nukeAndReload();
            })(); });

        // Per-entry and per-area clear buttons are rendered dynamically, so
        // delegate their clicks from the stable container.
        this.sectionsEl.addEventListener('click', (ev) => { this.onSectionClick(ev); });

        void this.refresh();
    }

    private onSectionClick(ev: MouseEvent): void {
        const btn = (ev.target as HTMLElement).closest<HTMLButtonElement>('button[data-action]');
        if (!btn || btn.disabled) return;
        const area = btn.dataset.area as StorageArea;
        if (btn.dataset.action === 'clear-all') void this.clearArea(area);
        else if (btn.dataset.action === 'clear-one') void this.clearEntry(area, btn.dataset.name ?? '');
    }

    private async refresh(): Promise<void> {
        const [caches, dbs] = await Promise.all([listCaches(), listDatabases()]);
        const local = listLocalStorage();
        const session = listSessionStorage();

        const frag = document.createDocumentFragment();
        frag.append(
            cacheSection(caches),
            idbSection(dbs),
            webStorageSection('local', local),
            webStorageSection('session', session),
        );
        this.sectionsEl.replaceChildren(frag);
    }

    private async clearArea(area: StorageArea): Promise<void> {
        if (!confirm(`Clear ALL of ${AREA_LABELS[area]}?`)) return;
        const result = area === 'caches' ? await clearAllCaches()
            : area === 'idb' ? await deleteAllDatabases()
                : area === 'local' ? clearLocalStorage()
                    : clearSessionStorage();
        this.report(result);
        await this.refresh();
    }

    private async clearEntry(area: StorageArea, name: string): Promise<void> {
        if (!name || !confirm(`Clear "${name}" from ${AREA_LABELS[area]}?`)) return;
        const result = area === 'caches' ? await clearCache(name)
            : area === 'idb' ? await deleteDatabaseNamed(name)
                : area === 'local' ? removeLocalStorageKey(name)
                    : removeSessionStorageKey(name);
        this.report(result);
        await this.refresh();
    }

    private report(result: unknown): void {
        this.outputEl.hidden = false;
        this.outputEl.textContent = JSON.stringify(result, null, 2);
    }
}

function cacheSection(result: Awaited<ReturnType<typeof listCaches>>): HTMLElement {
    if (!result.ok) return buildSection('caches', { error: result.error });
    const rows = result.caches.map((c: CacheInfo): Row => ({
        name: c.name,
        meta: `${c.entries} ${c.entries === 1 ? 'entry' : 'entries'}`,
        hint: HINTS.caches[c.name],
    }));
    return buildSection('caches', { summary: `${rows.length} ${rows.length === 1 ? 'cache' : 'caches'}`, rows });
}

function idbSection(result: Awaited<ReturnType<typeof listDatabases>>): HTMLElement {
    if (!result.ok) return buildSection('idb', { error: result.error });
    const rows = result.databases.map((name: string): Row => ({
        name,
        meta: 'database',
        hint: HINTS.idb[name],
    }));
    return buildSection('idb', { summary: `${rows.length} ${rows.length === 1 ? 'database' : 'databases'}`, rows });
}

function webStorageSection(area: 'local' | 'session', result: ReturnType<typeof listLocalStorage>): HTMLElement {
    if (!result.ok) return buildSection(area, { error: result.error });
    const info: WebStorageInfo = result;
    const rows = info.entries.map((e): Row => ({
        name: e.key,
        meta: formatBytes(e.bytes),
        hint: HINTS[area][e.key],
    }));
    const summary = `${rows.length} ${rows.length === 1 ? 'key' : 'keys'} · ${formatBytes(info.bytes)}`;
    return buildSection(area, { summary, rows });
}

function buildSection(area: StorageArea, body: { summary: string; rows: Row[] } | { error: string }): HTMLElement {
    const section = document.createElement('section');
    section.className = 'debug-storage-section';
    section.dataset.area = area;

    const head = document.createElement('div');
    head.className = 'debug-storage-head';

    const title = document.createElement('span');
    title.className = 'debug-storage-title';
    title.textContent = AREA_LABELS[area];

    const summary = document.createElement('span');
    summary.className = 'debug-storage-summary';

    const clearAll = makeButton('Clear all', { action: 'clear-all', area });
    clearAll.setAttribute('data-testid', CLEAR_ALL_TESTID[area]);

    head.append(title, summary, clearAll);
    section.append(head);

    if ('error' in body) {
        summary.textContent = 'error';
        clearAll.disabled = true;
        section.append(line('debug-storage-error', body.error));
        return section;
    }

    summary.textContent = body.summary;
    if (body.rows.length === 0) {
        clearAll.disabled = true;
        section.append(line('debug-storage-empty', 'empty'));
        return section;
    }

    const list = document.createElement('ul');
    list.className = 'debug-storage-list';
    for (const row of body.rows) list.append(buildRow(area, row));
    section.append(list);
    return section;
}

function buildRow(area: StorageArea, row: Row): HTMLElement {
    const li = document.createElement('li');
    li.className = 'debug-storage-row';

    const main = document.createElement('div');
    main.className = 'debug-storage-row-main';

    const name = document.createElement('span');
    name.className = 'debug-storage-name';
    name.textContent = row.name;
    main.append(name);

    if (row.hint) {
        const hint = document.createElement('span');
        hint.className = 'debug-storage-hint';
        hint.textContent = row.hint;
        main.append(hint);
    }

    const meta = document.createElement('span');
    meta.className = 'debug-storage-row-meta';
    meta.textContent = row.meta;

    const clear = makeButton('Clear', { action: 'clear-one', area, name: row.name });

    li.append(main, meta, clear);
    return li;
}

function makeButton(label: string, data: { action: string; area: StorageArea; name?: string }): HTMLButtonElement {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'debug-btn';
    btn.textContent = label;
    btn.dataset.action = data.action;
    btn.dataset.area = data.area;
    if (data.name !== undefined) btn.dataset.name = data.name;
    return btn;
}

function line(className: string, text: string): HTMLElement {
    const p = document.createElement('p');
    p.className = className;
    p.textContent = text;
    return p;
}

if (!customElements.get('debug-storage-panel')) {
    customElements.define('debug-storage-panel', DebugStoragePanel);
}
