import { collectDbInfo, formatBytes } from '../../../../services/debug/db-info.js';
import { DbService } from '../../../../db/db.service.js';
import { SyncService } from '../../../../services/sync/sync.service.js';
import { refreshIfStale } from '../../../../services/sync/snapshot-refresh.service.js';
import { downloadAndLoadSnapshot } from '../../../../db/db-snapshot.service.js';

const template = document.createElement('template');
template.innerHTML = `
<details class="debug-panel" open>
    <summary>Database</summary>
    <pre class="debug-code" data-role="summary">Loading…</pre>
    <pre class="debug-code" data-role="details"></pre>
    <pre class="debug-code" data-role="output"></pre>
    <div class="debug-toolbar">
        <button class="debug-btn" type="button" data-testid="db-refresh">Refresh</button>
        <button class="debug-btn" type="button" data-testid="db-pull-snapshot">Pull snapshot</button>
        <button class="debug-btn" type="button" data-testid="db-refresh-if-stale">Refresh if stale</button>
        <button class="debug-btn" type="button" data-testid="db-sync">Sync (push + pull)</button>
    </div>
</details>
`;

export class DebugDatabasePanel extends HTMLElement {
    private initialized = false;

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        this.appendChild(template.content.cloneNode(true));

        const summaryEl = this.querySelector<HTMLPreElement>('[data-role="summary"]')!;
        const detailsEl = this.querySelector<HTMLPreElement>('[data-role="details"]')!;
        const outputEl = this.querySelector<HTMLPreElement>('[data-role="output"]')!;

        const refresh = async () => {
            summaryEl.textContent = 'Loading…';
            try {
                const info = await collectDbInfo({
                    driver: DbService.getInstance().driver,
                    storage: typeof navigator !== 'undefined' ? navigator.storage : undefined,
                });
                const usagePct = info.storage?.usage != null && info.storage.quota
                    ? `${((info.storage.usage / info.storage.quota) * 100).toFixed(2)}%`
                    : 'unknown';
                summaryEl.textContent = [
                    `DB size:         ${formatBytes(info.sizeBytes)} (${info.pageCount ?? '?'} × ${info.pageSize ?? '?'} bytes/page)`,
                    `Pending changes: ${info.pendingChanges ?? '?'}`,
                    `Storage used:    ${formatBytes(info.storage?.usage ?? null)} of ${formatBytes(info.storage?.quota ?? null)} (${usagePct})`,
                    `OPFS persisted:  ${info.storage?.persisted ?? 'unknown'}`,
                ].join('\n');
                detailsEl.textContent = JSON.stringify({ tables: info.tables, driverError: info.driverError }, null, 2);
            } catch (err) {
                const msg = err instanceof Error ? (err.stack ?? err.message) : String(err);
                summaryEl.textContent = `Failed to collect DB info: ${msg}`;
                detailsEl.textContent = '';
            }
        };

        this.querySelector<HTMLButtonElement>('[data-testid="db-refresh"]')!
            .addEventListener('click', () => { void refresh(); });

        this.querySelector<HTMLButtonElement>('[data-testid="db-pull-snapshot"]')!
            .addEventListener('click', () => { void (async () => {
                outputEl.textContent = 'Downloading snapshot…';
                try {
                    const loaded = await downloadAndLoadSnapshot({ dbService: DbService.getInstance() });
                    outputEl.textContent = JSON.stringify({ loaded }, null, 2);
                } catch (err) {
                    outputEl.textContent = err instanceof Error ? (err.stack ?? err.message) : String(err);
                }
                await refresh();
            })(); });

        this.querySelector<HTMLButtonElement>('[data-testid="db-refresh-if-stale"]')!
            .addEventListener('click', () => { void (async () => {
                outputEl.textContent = 'Checking snapshot freshness…';
                try {
                    const result = await refreshIfStale();
                    outputEl.textContent = JSON.stringify(result, null, 2);
                } catch (err) {
                    outputEl.textContent = err instanceof Error ? (err.stack ?? err.message) : String(err);
                }
                await refresh();
            })(); });

        this.querySelector<HTMLButtonElement>('[data-testid="db-sync"]')!
            .addEventListener('click', () => { void (async () => {
                outputEl.textContent = 'Syncing…';
                try {
                    const result = await SyncService.syncPendingChanges();
                    outputEl.textContent = JSON.stringify(result, null, 2);
                } catch (err) {
                    outputEl.textContent = err instanceof Error ? (err.stack ?? err.message) : String(err);
                }
                await refresh();
            })(); });

        void refresh();
    }
}

if (!customElements.get('debug-database-panel')) {
    customElements.define('debug-database-panel', DebugDatabasePanel);
}
