import { buildSectionPage } from '../../../utils/section-page.utils.js';
import './debug-logs-panel/debug-logs-panel.component.js';
import './debug-connectivity-panel/debug-connectivity-panel.component.js';
import './debug-database-panel/debug-database-panel.component.js';
import './debug-install-panel/debug-install-panel.component.js';
import './debug-sw-panel/debug-sw-panel.component.js';
import './debug-storage-panel/debug-storage-panel.component.js';
import type { ScreenComponent } from '../../../types/screen-component.js';

const template = document.createElement('template');
template.innerHTML = `
<p>In-app diagnostics. All errors are shown raw so they are instantly actionable on mobile.</p>
<debug-logs-panel></debug-logs-panel>
<debug-connectivity-panel></debug-connectivity-panel>
<debug-database-panel></debug-database-panel>
<debug-install-panel></debug-install-panel>
<debug-sw-panel></debug-sw-panel>
<debug-storage-panel></debug-storage-panel>
`;

export class DebugScreen extends HTMLElement implements ScreenComponent {
    setLoading(): void {}
    setError(_err: unknown): void {}
    clearStatus(): void {}
    private initialized = false;

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Debug', 'extra', '/debug');
        page.content.appendChild(template.content.cloneNode(true));
    }
}

if (!customElements.get('debug-screen')) {
    customElements.define('debug-screen', DebugScreen);
}
