import type { Result } from './sw-controls.js';

export interface CacheInfo {
    name: string;
    entries: number;
}

export async function listCaches(): Promise<Result<{ caches: CacheInfo[] }>> {
    if (typeof caches === 'undefined') {
        return { ok: false, error: 'Cache API not available in this context' };
    }
    try {
        const names = await caches.keys();
        const info = await Promise.all(names.map(async (name): Promise<CacheInfo> => {
            const cache = await caches.open(name);
            const keys = await cache.keys();
            return { name, entries: keys.length };
        }));
        return { ok: true, caches: info };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

export async function clearAllCaches(): Promise<Result<{ cleared: string[] }>> {
    if (typeof caches === 'undefined') {
        return { ok: false, error: 'Cache API not available in this context' };
    }
    try {
        const names = await caches.keys();
        await Promise.all(names.map((n) => caches.delete(n)));
        return { ok: true, cleared: names };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

/** Delete a single named cache (granular counterpart to {@link clearAllCaches}). */
export async function clearCache(name: string): Promise<Result<{ cleared: string }>> {
    if (typeof caches === 'undefined') {
        return { ok: false, error: 'Cache API not available in this context' };
    }
    try {
        const existed = await caches.delete(name);
        if (!existed) return { ok: false, error: `Cache "${name}" not found` };
        return { ok: true, cleared: name };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

export async function listDatabases(): Promise<Result<{ databases: string[] }>> {
    try {
        const idb = indexedDB as unknown as { databases?: () => Promise<Array<{ name?: string }>> };
        if (typeof idb.databases !== 'function') {
            return { ok: false, error: 'indexedDB.databases() not supported by this browser' };
        }
        const list = await idb.databases();
        const names = list.map((d) => d.name).filter((n): n is string => typeof n === 'string');
        return { ok: true, databases: names };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

export async function deleteAllDatabases(): Promise<Result<{ deleted: string[] }>> {
    const listed = await listDatabases();
    if (!listed.ok) return listed;

    try {
        await Promise.all(listed.databases.map((name) => deleteDatabase(name)));
        return { ok: true, deleted: listed.databases };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

/** Delete a single named IndexedDB database (granular counterpart to {@link deleteAllDatabases}). */
export async function deleteDatabaseNamed(name: string): Promise<Result<{ deleted: string }>> {
    try {
        await deleteDatabase(name);
        return { ok: true, deleted: name };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

function deleteDatabase(name: string): Promise<void> {
    return new Promise((resolve, reject) => {
        const req = indexedDB.deleteDatabase(name);
        req.onsuccess = () => resolve();
        req.onerror = () => reject(new Error(`Failed to delete IndexedDB "${name}"`));
        req.onblocked = () => resolve();
    });
}

export interface StorageEntry {
    key: string;
    bytes: number;
}

export interface WebStorageInfo {
    entries: StorageEntry[];
    bytes: number;
}

function listWebStorage(store: Storage): Result<WebStorageInfo> {
    try {
        const entries: StorageEntry[] = [];
        let bytes = 0;
        for (let i = 0; i < store.length; i++) {
            const key = store.key(i);
            if (key === null) continue;
            // Approximate UTF-16 byte cost: key + value, 2 bytes per char.
            const value = store.getItem(key) ?? '';
            const entryBytes = (key.length + value.length) * 2;
            entries.push({ key, bytes: entryBytes });
            bytes += entryBytes;
        }
        entries.sort((a, b) => a.key.localeCompare(b.key));
        return { ok: true, entries, bytes };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

function removeStorageKey(store: Storage, key: string): Result<{ removed: string }> {
    try {
        store.removeItem(key);
        return { ok: true, removed: key };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

function clearWebStorage(store: Storage): Result<{ cleared: number }> {
    try {
        const cleared = store.length;
        store.clear();
        return { ok: true, cleared };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

export const listLocalStorage = (): Result<WebStorageInfo> => listWebStorage(localStorage);
export const listSessionStorage = (): Result<WebStorageInfo> => listWebStorage(sessionStorage);

export const clearLocalStorage = (): Result<{ cleared: number }> => clearWebStorage(localStorage);
export const clearSessionStorage = (): Result<{ cleared: number }> => clearWebStorage(sessionStorage);

export const removeLocalStorageKey = (key: string): Result<{ removed: string }> =>
    removeStorageKey(localStorage, key);
export const removeSessionStorageKey = (key: string): Result<{ removed: string }> =>
    removeStorageKey(sessionStorage, key);

export async function nukeAndReload(): Promise<void> {
    const { unregisterSw } = await import('./sw-controls.js');
    await unregisterSw();
    await clearAllCaches();
    await deleteAllDatabases();
    // localStorage is intentionally preserved so the device identity used for
    // client-log correlation survives a nuke; clear it explicitly if needed.
    clearSessionStorage();
    location.reload();
}

function formatError(err: unknown): string {
    if (err instanceof Error) return err.stack ?? err.message;
    return String(err);
}
