import { getDeviceId, getDeviceLabel, setDeviceLabel } from '../../../../services/debug/device-identity.js';
import {
    snapshotInstall, queryPermissions, requestNotificationPermission, persistStorage,
    isStoragePersisted, DEFAULT_PERMISSION_NAMES,
} from '../../../../services/debug/install-info.js';

const template = document.createElement('template');
template.innerHTML = `
<details class="debug-panel" open>
    <summary>Install &amp; Permissions</summary>
    <div class="debug-device-row">
        <div data-testid="device-id"></div>
        <input class="debug-input" type="text" data-testid="device-label">
    </div>
    <pre class="debug-code" data-role="install"></pre>
    <pre class="debug-code" data-role="permissions"></pre>
    <pre class="debug-code" data-role="output"></pre>
    <div class="debug-toolbar">
        <button class="debug-btn" type="button" data-testid="install-refresh">Refresh</button>
        <button class="debug-btn" type="button" data-testid="install-request-notifications">Request notifications</button>
        <button class="debug-btn" type="button" data-testid="install-persist-storage">Persist storage</button>
    </div>
</details>
`;

export class DebugInstallPanel extends HTMLElement {
    private initialized = false;

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        this.appendChild(template.content.cloneNode(true));

        const deviceIdLabel = this.querySelector<HTMLElement>('[data-testid="device-id"]')!;
        const labelInput = this.querySelector<HTMLInputElement>('[data-testid="device-label"]')!;
        const installEl = this.querySelector<HTMLPreElement>('[data-role="install"]')!;
        const permissionsEl = this.querySelector<HTMLPreElement>('[data-role="permissions"]')!;
        const outputEl = this.querySelector<HTMLPreElement>('[data-role="output"]')!;

        labelInput.addEventListener('change', () => {
            const value = labelInput.value.trim();
            if (!value) {
                labelInput.value = getDeviceLabel();
                return;
            }
            setDeviceLabel(value);
        });

        const refresh = async () => {
            deviceIdLabel.textContent = `device_id: ${getDeviceId()}`;
            labelInput.value = getDeviceLabel();
            installEl.textContent = JSON.stringify({
                ...snapshotInstall(),
                storagePersisted: await isStoragePersisted(),
            }, null, 2);
            permissionsEl.textContent = JSON.stringify(
                await queryPermissions(DEFAULT_PERMISSION_NAMES),
                null, 2,
            );
        };

        this.querySelector<HTMLButtonElement>('[data-testid="install-refresh"]')!
            .addEventListener('click', () => { void refresh(); });

        this.querySelector<HTMLButtonElement>('[data-testid="install-request-notifications"]')!
            .addEventListener('click', () => { void (async () => {
                outputEl.textContent = JSON.stringify(await requestNotificationPermission(), null, 2);
                await refresh();
            })(); });

        this.querySelector<HTMLButtonElement>('[data-testid="install-persist-storage"]')!
            .addEventListener('click', () => { void (async () => {
                outputEl.textContent = JSON.stringify(await persistStorage(), null, 2);
                await refresh();
            })(); });

        void refresh();
    }
}

if (!customElements.get('debug-install-panel')) {
    customElements.define('debug-install-panel', DebugInstallPanel);
}
