import type { Result } from './sw-controls.js';

export type DisplayMode = 'standalone' | 'minimal-ui' | 'fullscreen' | 'browser';

export interface InstallSnapshot {
    displayMode: DisplayMode;
    /** True iff displayMode is standalone/minimal-ui/fullscreen. */
    installed: boolean;
    standalone: boolean;
    minimalUi: boolean;
    fullscreen: boolean;
}

export function snapshotInstall(): InstallSnapshot {
    const standalone = window.matchMedia('(display-mode: standalone)').matches;
    const minimalUi = window.matchMedia('(display-mode: minimal-ui)').matches;
    const fullscreen = window.matchMedia('(display-mode: fullscreen)').matches;
    const displayMode: DisplayMode = standalone ? 'standalone'
        : fullscreen ? 'fullscreen'
        : minimalUi ? 'minimal-ui'
        : 'browser';
    return {
        displayMode,
        installed: standalone || minimalUi || fullscreen,
        standalone, minimalUi, fullscreen,
    };
}

export type PermissionName =
    | 'notifications'
    | 'push'
    | 'periodic-background-sync'
    | 'background-sync'
    | 'persistent-storage'
    | 'geolocation'
    | 'camera'
    | 'microphone';

export const DEFAULT_PERMISSION_NAMES: PermissionName[] = [
    'notifications',
    'push',
    'periodic-background-sync',
    'background-sync',
    'persistent-storage',
];

export interface PermissionInfo {
    name: PermissionName;
    state: 'granted' | 'denied' | 'prompt' | 'error' | 'unsupported';
    error?: string;
}

export async function queryPermissions(names: PermissionName[]): Promise<PermissionInfo[]> {
    if (!('permissions' in navigator)) {
        return names.map((name) => ({ name, state: 'unsupported' as const }));
    }
    return Promise.all(names.map(async (name): Promise<PermissionInfo> => {
        try {
            // Chrome rejects `push` without userVisibleOnly:true. Every other
            // permission name rejects that descriptor, so only apply it to push.
            const descriptor: PermissionDescriptor = name === 'push'
                ? ({ name, userVisibleOnly: true } as unknown as PermissionDescriptor)
                : ({ name } as PermissionDescriptor);
            const status = await navigator.permissions.query(descriptor);
            return { name, state: status.state as PermissionInfo['state'] };
        } catch (err) {
            return { name, state: 'error', error: err instanceof Error ? err.message : String(err) };
        }
    }));
}

export async function requestNotificationPermission(): Promise<Result<{ state: NotificationPermission }>> {
    try {
        if (typeof Notification === 'undefined') {
            return { ok: false, error: 'Notification API not available' };
        }
        const state = await Notification.requestPermission();
        return { ok: true, state };
    } catch (err) {
        return { ok: false, error: err instanceof Error ? err.message : String(err) };
    }
}

export async function persistStorage(): Promise<Result<{ persisted: boolean }>> {
    try {
        if (!navigator.storage?.persist) {
            return { ok: false, error: 'navigator.storage.persist() not available' };
        }
        const persisted = await navigator.storage.persist();
        return { ok: true, persisted };
    } catch (err) {
        return { ok: false, error: err instanceof Error ? err.message : String(err) };
    }
}

export async function isStoragePersisted(): Promise<boolean> {
    if (!navigator.storage?.persisted) return false;
    return navigator.storage.persisted();
}
